import React from 'react';
import { PlanetData } from '../types';

interface UIOverlayProps {
  selectedPlanet: PlanetData | null;
  onClose: () => void;
  isPaused: boolean;
  togglePause: () => void;
  simulationSpeed: number;
  setSimulationSpeed: (speed: number) => void;
  isStarshipActive: boolean;
  toggleStarship: () => void;
  showPluto: boolean;
  togglePluto: () => void;
  toggleGestureMode: () => void;
  isGestureMode: boolean;
}

export const UIOverlay: React.FC<UIOverlayProps> = ({ 
  selectedPlanet, 
  onClose,
  isPaused,
  togglePause,
  simulationSpeed,
  setSimulationSpeed,
  isStarshipActive,
  toggleStarship,
  showPluto,
  togglePluto,
  toggleGestureMode,
  isGestureMode
}) => {
  // Calculations for kids
  const calculateTravelTime = (planet: PlanetData) => {
    const distanceKm = planet.realDistance * 1000000;

    // Light speed: ~300,000 km/s (~18,000,000 km/min)
    const lightMinutes = (planet.realDistance / 18).toFixed(1);

    // Airplane: ~900 km/h
    const planeHours = distanceKm / 900;
    const planeYears = (planeHours / 24 / 365).toFixed(1);

    // Fast Rocket: ~40,000 km/h
    const rocketHours = distanceKm / 40000;
    const rocketDays = Math.round(rocketHours / 24);
    const rocketYears = (rocketHours / 24 / 365).toFixed(1);

    const rocketTimeDisplay = rocketDays > 365 
      ? `${rocketYears} 年` 
      : `${rocketDays} 天`;

    return { lightMinutes, planeYears, rocketTimeDisplay };
  };

  const travelInfo = selectedPlanet ? calculateTravelTime(selectedPlanet) : null;

  // Determine if we should show travel time (Not for Earth or Sun)
  const showTravelTime = selectedPlanet && selectedPlanet.id !== 'earth' && selectedPlanet.id !== 'sun';
  // Determine if we should show Habitat Info (Only for Earth)
  const isEarth = selectedPlanet?.id === 'earth';

  const getPlanetTheme = (planet: PlanetData) => {
    if (planet.id === 'sun') return { icon: '☀️', type: '恒星' };
    if (planet.id === 'earth') return { icon: '🌍', type: '生命家园' };
    if (planet.id === 'pluto') return { icon: '❄️', type: '矮行星' };
    if (planet.realDistance < 200) return { icon: '🪨', type: '岩石系' }; 
    if (planet.hasRings) return { icon: '🪐', type: '飞行系' };
    if (planet.realDistance > 2000) return { icon: '🧊', type: '冰系' };
    return { icon: '🎈', type: '气体系' };
  };

  const styles = `
    @keyframes spin-slow {
      0% { transform: rotate(0deg); }
      100% { transform: rotate(360deg); }
    }
    @keyframes float {
      0%, 100% { transform: translateY(0); }
      50% { transform: translateY(-5px); }
    }
    @keyframes pulse-glow {
      0%, 100% { box-shadow: 0 0 10px rgba(6,182,212,0.5); }
      50% { box-shadow: 0 0 20px rgba(6,182,212,0.8); }
    }
    @keyframes pop-up {
      0% { transform: scale(0.5) translateY(50px); opacity: 0; }
      80% { transform: scale(1.05) translateY(-10px); opacity: 1; }
      100% { transform: scale(1) translateY(0); }
    }
    @keyframes fade-in {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    @keyframes scan-line {
      0% { transform: translateX(-150%) skewX(-20deg); }
      100% { transform: translateX(250%) skewX(-20deg); }
    }
    .animate-pop-up { animation: pop-up 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
    .animate-fade-in { animation: fade-in 0.2s ease-out forwards; }
    .animate-float { animation: float 4s ease-in-out infinite; }
    .animate-scan { animation: scan-line 3s cubic-bezier(0.4, 0, 0.2, 1) infinite; }

    /* Custom Scrollbar */
    .pika-scrollbar::-webkit-scrollbar { width: 6px; }
    .pika-scrollbar::-webkit-scrollbar-track { background: rgba(255,255,255,0.1); border-radius: 3px; }
    .pika-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.3); border-radius: 3px; }

    /* Common Button Base */
    .action-btn {
      width: 4rem; height: 4rem;
      border: 3px solid rgba(255,255,255,0.2);
      border-radius: 50%;
      box-shadow: 0 4px 15px rgba(0,0,0,0.5);
      backdrop-filter: blur(10px);
      display: flex; flex-direction: column; align-items: center; justify-content: center;
      transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
      position: relative;
      overflow: hidden;
    }
    .action-btn::before {
      content: ''; position: absolute; inset: 0; 
      background: radial-gradient(circle at top left, rgba(255,255,255,0.4), transparent 70%);
      opacity: 0.5;
    }
    .action-btn:active { transform: scale(0.95); }
    .action-btn:hover { border-color: rgba(255,255,255,0.8); transform: translateY(-2px); }

    /* Rocket Button Style */
    .rocket-btn {
      background: linear-gradient(135deg, #3b82f6, #1d4ed8);
    }
    .rocket-btn.inactive { background: rgba(30, 41, 59, 0.8); border-color: rgba(255,255,255,0.1); }
    .rocket-btn .indicator {
       position: absolute; top: 10px; right: 10px;
       width: 8px; height: 8px; border-radius: 50%;
       box-shadow: 0 0 5px currentColor;
    }

    /* Pluto Button Style */
    .pluto-btn {
      background: linear-gradient(135deg, #8b5cf6, #5b21b6);
    }
    .pluto-btn.inactive { background: rgba(30, 41, 59, 0.8); border-color: rgba(255,255,255,0.1); }
    .pluto-btn .indicator {
       position: absolute; top: 10px; right: 10px;
       width: 8px; height: 8px; border-radius: 50%;
       box-shadow: 0 0 5px currentColor;
    }

    /* Gesture Button Style */
    .gesture-btn {
      background: linear-gradient(135deg, #10b981, #047857);
    }
    .gesture-btn.inactive { background: rgba(30, 41, 59, 0.8); border-color: rgba(255,255,255,0.1); }
    .gesture-btn .indicator {
       position: absolute; top: 10px; right: 10px;
       width: 8px; height: 8px; border-radius: 50%;
       box-shadow: 0 0 5px currentColor;
    }

    .gesture-active-pulse {
       animation: pulse-green 2s infinite;
    }
    @keyframes pulse-green {
      0% { box-shadow: 0 0 0 0 rgba(16, 185, 129, 0.7); }
      70% { box-shadow: 0 0 0 10px rgba(16, 185, 129, 0); }
      100% { box-shadow: 0 0 0 0 rgba(16, 185, 129, 0); }
    }

    /* Sci-Fi Text Shadow */
    .text-glow {
      text-shadow: 0 0 5px rgba(34, 211, 238, 0.8);
    }
    .warp-panel-clip {
       clip-path: polygon(
         10px 0, 100% 0, 
         100% calc(100% - 10px), calc(100% - 10px) 100%, 
         0 100%, 0 10px
       );
    }
    .warp-cell-clip {
       transform: skewX(-20deg);
    }
    .warp-cell-content-reset {
       transform: skewX(20deg);
    }
  `;

  // Define speed steps
  const speedSteps = [0, 1, 5, 10, 20];

  // Helper for Warp Cell Color
  const getWarpCellClass = (speed: number, currentSpeed: number) => {
      const isActive = currentSpeed >= speed && speed !== 0;
      const isSelected = currentSpeed === speed;
      const isPause = speed === 0;

      // Base Styles
      let classes = "h-9 w-full border-b-2 border-r-2 transition-all duration-300 relative overflow-hidden group ";

      if (isPause) {
          if (isSelected) return classes + "bg-red-500/80 border-red-300 shadow-[0_0_15px_rgba(239,68,68,0.6)]";
          return classes + "bg-slate-900/60 border-slate-700 hover:bg-red-900/40";
      }

      if (isActive) {
          if (speed >= 20) return classes + "bg-red-600 border-red-300 shadow-[0_0_15px_rgba(239,68,68,0.8)]";
          if (speed >= 10) return classes + "bg-orange-500 border-orange-300 shadow-[0_0_15px_rgba(249,115,22,0.8)]";
          if (speed >= 5) return classes + "bg-cyan-500 border-cyan-200 shadow-[0_0_15px_rgba(6,182,212,0.8)]";
          return classes + "bg-blue-500 border-blue-300 shadow-[0_0_10px_rgba(59,130,246,0.8)]";
      }

      return classes + "bg-slate-900/60 border-slate-700 hover:bg-cyan-900/40";
  };

  return (
    <>
      <style>{styles}</style>
      <div className="absolute inset-0 pointer-events-none flex flex-col justify-between p-4 sm:p-6 z-10 font-sans select-none">

        {/* Header Section */}
        <header className="flex flex-col sm:flex-row justify-between items-start pointer-events-auto">
          <div>
            <h1 className="text-4xl sm:text-6xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-300 via-orange-400 to-red-500 drop-shadow-[0_4px_4px_rgba(0,0,0,0.5)] font-[ZCOOL KuaiLe] tracking-wider animate-pop-up">
              太阳和它的朋友们
            </h1>
            <p className="text-white/80 text-sm sm:text-base mt-2 bg-black/30 backdrop-blur-md px-3 py-1 rounded-full inline-block border border-white/10">
              🌌 3D 太阳系互动百科 • 专为好奇宝宝设计
            </p>
          </div>
        </header>

        {/* --- MAIN CONTENT AREA --- */}
        <div className="flex-1 relative">

            {/* --- LEFT SIDE: ACTION BUTTONS --- */}
            <div className="absolute top-1/2 -translate-y-1/2 left-0 flex flex-col gap-6 pointer-events-auto">
                {/* 1. Starship Button */}
                <div className="flex items-center gap-3 group">
                  <button 
                    onClick={toggleStarship}
                    className={`action-btn rocket-btn ${!isStarshipActive && 'inactive'}`}
                  >
                    <span className="text-2xl filter drop-shadow-md">🚀</span>
                    <div className={`indicator ${isStarshipActive ? 'bg-green-400' : 'bg-red-400'}`} />
                  </button>
                  <span className="bg-black/60 text-white px-2 py-1 rounded text-xs opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap backdrop-blur-sm border border-white/10">
                    星际飞船
                  </span>
                </div>

                {/* 2. Pluto Toggle */}
                <div className="flex items-center gap-3 group">
                   <button 
                     onClick={togglePluto}
                     className={`action-btn pluto-btn ${!showPluto && 'inactive'}`}
                   >
                     <span className="text-2xl filter drop-shadow-md">❤️</span>
                     <div className={`indicator ${showPluto ? 'bg-green-400' : 'bg-gray-400'}`} />
                   </button>
                   <span className="bg-black/60 text-white px-2 py-1 rounded text-xs opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap backdrop-blur-sm border border-white/10">
                     {showPluto ? "隐藏冥王星" : "显示冥王星"}
                   </span>
                </div>

                {/* 3. Gesture Control */}
                <div className="flex items-center gap-3 group">
                   <button 
                     onClick={toggleGestureMode}
                     className={`action-btn gesture-btn ${!isGestureMode && 'inactive'} ${isGestureMode && 'gesture-active-pulse'}`}
                   >
                     <span className="text-2xl filter drop-shadow-md">👋</span>
                     <div className={`indicator ${isGestureMode ? 'bg-green-400' : 'bg-gray-400'}`} />
                   </button>
                   <span className="bg-black/60 text-white px-2 py-1 rounded text-xs opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap backdrop-blur-sm border border-white/10">
                     {isGestureMode ? "关闭手势" : "手势控制"}
                   </span>
                </div>
            </div>

            {/* --- RIGHT SIDE: WARP DRIVE (Speed Control) --- */}
            <div className="absolute top-1/2 -translate-y-1/2 right-0 pointer-events-auto">
               <div className="warp-panel-clip bg-slate-900/80 border border-cyan-500/30 backdrop-blur-md p-4 w-44 shadow-[0_0_30px_rgba(6,182,212,0.15)] relative overflow-hidden">

                  {/* Holographic Scanline Overlay */}
                  <div className="absolute inset-0 bg-[linear-gradient(transparent_50%,rgba(6,182,212,0.05)_50%)] bg-[length:100%_4px] pointer-events-none z-0"></div>
                  <div className="absolute top-0 left-0 w-full h-1 bg-cyan-400/50 blur-[2px] animate-[scan-line_4s_linear_infinite] z-0"></div>

                  {/* Header */}
                  <div className="relative z-10 mb-3 border-b border-cyan-500/30 pb-2">
                     <h3 className="text-cyan-400 font-mono font-bold text-lg leading-none tracking-tight text-glow">
                        TIME WARP
