                     <div className="flex justify-between items-end mt-1">
                        <span className="text-[10px] text-cyan-600 font-mono tracking-widest">时间流速</span>
                        <span className="text-[10px] text-cyan-300 font-mono">{simulationSpeed}x</span>
                     </div>
                  </div>

                  {/* Energy Cells Stack */}
                  <div className="flex flex-col gap-1.5 relative z-10">
                     {/* We reverse the array to stack typical UI bottom-up, BUT for this design top-down list reads better as a menu */}
                     {[...speedSteps].reverse().map((speed) => {
                         const isActive = simulationSpeed >= speed && speed !== 0;
                         const isSelected = simulationSpeed === speed;

                         return (
                            <button
                               key={speed}
                               onClick={() => setSimulationSpeed(speed)}
                               className={`
                                  ${getWarpCellClass(speed, simulationSpeed)}
                                  warp-cell-clip
                                  flex items-center justify-between px-4
                               `}
                            >
                               {/* Content (Un-skewed) */}
                               <div className="warp-cell-content-reset w-full flex justify-between items-center">
                                  <span className={`font-mono font-bold text-xs tracking-wider ${isActive || (speed === 0 && isSelected) ? 'text-white text-glow' : 'text-slate-500'}`}>
                                     {speed === 0 ? "⏸ STASIS" : `WARP ${speed}`}
                                  </span>

                                  {/* Active Indicators */}
                                  {(isActive || (speed === 0 && isSelected)) && (
                                     <div className="w-2 h-2 rounded-full bg-white shadow-[0_0_5px_white] animate-pulse"></div>
                                  )}
                               </div>

                               {/* Active Scan Effect within cell */}
                               {isActive && (
                                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent w-[200%] animate-scan pointer-events-none"></div>
                               )}
                            </button>
                         )
                     })}
                  </div>

                  {/* Footer Decorative Text */}
                  <div className="relative z-10 mt-3 pt-2 border-t border-cyan-500/20 text-right">
                     <span className="text-[8px] text-cyan-700 font-mono">SYS.OPTIMIZED // V.2.4</span>
                  </div>

               </div>
            </div>

            {/* --- CENTER: PLANET INFO CARD --- */}
            {selectedPlanet && (
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-lg px-4 pointer-events-none z-50">
                <div className="bg-black/60 backdrop-blur-xl rounded-3xl p-6 sm:p-8 text-white space-card-border pointer-events-auto animate-pop-up relative overflow-hidden group">

                  {/* Background Gradient Blob */}
                  <div 
                    className="absolute -top-20 -right-20 w-64 h-64 rounded-full opacity-30 blur-3xl pointer-events-none transition-colors duration-500"
                    style={{ backgroundColor: selectedPlanet.color }}
                  ></div>

                  {/* Close Button */}
                  <button 
                    onClick={onClose}
                    className="absolute top-4 right-4 w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center transition-colors z-20"
                  >
                    ✕
                  </button>

                  <div className="relative z-10">
                    <div className="flex items-center gap-4 mb-4">
                      <div 
                        className="w-16 h-16 rounded-full shadow-lg border-4 border-white/20 flex items-center justify-center text-3xl animate-float bg-black/40"
                        style={{ boxShadow: `0 0 30px ${selectedPlanet.color}60` }}
                      >
                         {getPlanetTheme(selectedPlanet).icon}
                      </div>
                      <div>
                        <h2 className="text-3xl font-bold font-[ZCOOL KuaiLe] tracking-wide mb-1 flex items-center gap-2">
                           {selectedPlanet.name}
                        </h2>
                        <div className="flex gap-2 text-xs font-mono opacity-80">
                           <span className="bg-white/10 px-2 py-0.5 rounded border border-white/10">
                              {getPlanetTheme(selectedPlanet).type}
                           </span>
                           {selectedPlanet.temperature && (
                             <span className="bg-white/10 px-2 py-0.5 rounded border border-white/10">
                               🌡 {selectedPlanet.temperature}
                             </span>
                           )}
                        </div>
                      </div>
                    </div>

                    <div className="space-y-4 max-h-[50vh] overflow-y-auto pr-2 pika-scrollbar">
                      <p className="text-lg leading-relaxed text-blue-50">
                        {selectedPlanet.description}
                      </p>

                      {/* Travel Time Box */}
                      {showTravelTime && travelInfo && (
                        <div className="bg-blue-900/30 rounded-xl p-4 border border-blue-400/30 relative overflow-hidden">
                           <div className="absolute top-0 left-0 w-1 h-full bg-blue-400/50"></div>
                           <h4 className="font-bold text-blue-200 text-sm mb-2 flex items-center gap-2">
                             🚀 宇宙飞船去这里要多久?
                           </h4>
                           <div className="grid grid-cols-2 gap-3 text-sm">
                              <div>
                                 <div className="text-white/50 text-xs">光速 (Light)</div>
                                 <div className="font-mono text-yellow-300 font-bold">{travelInfo.lightMinutes} 分钟</div>
                              </div>
                              <div>
                                 <div className="text-white/50 text-xs">普通火箭 (Rocket)</div>
                                 <div className="font-mono text-green-300 font-bold">{travelInfo.rocketTimeDisplay}</div>
                              </div>
                           </div>
                        </div>
                      )}

                      {isEarth && (
                        <div className="bg-green-900/30 rounded-xl p-4 border border-green-400/30">
                           <h4 className="font-bold text-green-200 text-sm mb-2">🌿 为什么只有地球有生命?</h4>
                           <ul className="text-sm space-y-2 text-green-50/80 list-disc list-inside">
                              <li>我们有<b>液态水</b> (Water)</li>
                              <li>距离太阳<b>不冷也不热</b></li>
                              <li>厚厚的<b>大气层</b>保护我们</li>
                           </ul>
                        </div>
                      )}

                      {selectedPlanet.funFact && (
                        <div className="bg-yellow-500/20 p-4 rounded-xl border border-yellow-500/30 flex gap-3">
                          <span className="text-2xl">💡</span>
                          <div>
                            <span className="font-bold text-yellow-200 block text-xs uppercase tracking-wider mb-1">Fun Fact</span>
                            <span className="text-sm text-yellow-50 italic">
                              "{selectedPlanet.funFact}"
                            </span>
                          </div>
                        </div>
                      )}

                      <div className="grid grid-cols-2 gap-3 text-xs opacity-70 font-mono mt-4 pt-4 border-t border-white/10">
                         <div>
                            <span className="block opacity-50">成分</span>
                            {selectedPlanet.composition}
                         </div>
                         <div>
                            <span className="block opacity-50">真实距离</span>
                            {selectedPlanet.realDistance} 百万公里
                         </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
        </div>

        {/* Footer Credit */}
        <div className="pointer-events-auto text-center mt-4">
           <a 
             href="https://github.com/google-gemini/solar-system-ar" 
             target="_blank" 
             rel="noreferrer"
             className="inline-flex items-center gap-2 text-white/40 hover:text-white/80 transition-colors text-xs font-mono bg-black/20 px-3 py-1 rounded-full border border-white/5 hover:border-white/20"
           >
             <span>Design with Gemini 2.0 Flash</span>
           </a>
        </div>

      </div>
    </>
  );
};
